export default function Certifications() {
  return (
    <section id="certifications" className="section-padding relative">
      <div className="section-max">
        <BlurReveal>
          <p
            className="text-xs uppercase tracking-[0.3em] mb-4"
            style={{ color: "var(--c-orange)", fontFamily: "var(--font-mono)" }}
          >
            Certifications
          </p>
          <h2
            className="text-section-title mb-4"
            style={{ fontFamily: "var(--font-heading)", color: "var(--c-text)" }}
          >
            <CountUp end={certCount} className="inline" /> AWS Certifications
          </h2>
          <p
            className="text-base mb-16"
            style={{ color: "var(--c-muted)", maxWidth: "500px" }}
          >
            Validated cloud expertise across architecture, development,
            machine learning, and security domains.
          </p>
        </BlurReveal>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
          {certifications.map((cert, i) => (
            <BlurReveal key={cert.code} delay={i * 0.05}>
              <TiltCard
                className="cert-card p-6 h-full"
                intensity={12}
              >
                <div className="flex items-start gap-4">
                  <div className="cert-logo flex-shrink-0">
                    <AWSLogo />
                  </div>
                  <div className="min-w-0">
                    <h3
                      className="text-sm font-medium mb-1 leading-tight"
                      style={{
                        fontFamily: "var(--font-heading)",
                        color: "var(--c-text)",
                        fontWeight: 400,
                      }}
                    >
                      {cert.name}
                    </h3>
                    <p
                      className="text-xs"
                      style={{ color: "var(--c-muted)", fontFamily: "var(--font-mono)" }}
                    >
                      {cert.code} · {cert.issueDate}
                    </p>
                  </div>
                </div>
              </TiltCard>
            </BlurReveal>
          ))}
        </div>
      </div>
    </section>
  );
}
